from datasets import load_dataset
import anthropic, json

client = anthropic.Anthropic()
mind2web = load_dataset("osunlp/Mind2Web", split="test_cross_domain")

def format_mind2web_step(action: dict, html_snippet: str) -> str:
    return (
        f"Task: {action['confirmed_task']}\n\n"
        f"Previous actions: {action.get('action_reprs', [])}\n\n"
        f"Current page HTML (truncated):\n{html_snippet[:3000]}\n\n"
        "What element should be interacted with next, and what action? "
        "Reply as JSON: {element_text: str, action: 'click'|'type'|'select', value: str|null}"
    )

def predict_action(task_item: dict, step_idx: int, model="claude-haiku-4-5-20251001") -> dict:
    step = task_item["actions"][step_idx]
    html = task_item["cleaned_html"][step_idx]

    resp = client.messages.create(
        model=model,
        max_tokens=256,
        system="You are a web navigation agent. Output only valid JSON.",
        messages=[{"role": "user", "content": format_mind2web_step(step, html)}],
    )
    try:
        return json.loads(resp.content[0].text.strip())
    except json.JSONDecodeError:
        return {}

def element_accuracy(pred: dict, gold: dict) -> bool:
    # Check if predicted element text matches any of the gold candidate elements
    pred_text = pred.get("element_text", "").lower().strip()
    for candidate in gold.get("pos_candidates", []):
        if candidate.get("clean_text", "").lower().strip() == pred_text:
            return True
    return False

