def vwa_step(obs: dict, task_intent: str, model="claude-haiku-4-5-20251001") -> str:
    screenshot_b64 = encode_screenshot(obs["screenshot"])

    content = [
        {
            "type": "image",
            "source": {
                "type": "base64",
                "media_type": "image/png",
                "data": screenshot_b64,
            },
        },
        {
            "type": "text",
            "text": (
                f"Task: {task_intent}\n\n"
                f"URL: {obs['url']}\n\n"
                f"AXTree (truncated):\n{obs['axtree_txt'][:2000]}\n\n"
                "Output a single BrowserGym action. "
                "Use the screenshot to locate elements not visible in the AXTree."
            ),
        },
    ]

    resp = client.messages.create(
        model=model,
        max_tokens=256,
        system="You are a web agent. Output exactly one BrowserGym action string.",
        messages=[{"role": "user", "content": content}],
    )
    return resp.content[0].text.strip()

# Same agent code; change only the env ID
BENCHMARK_ENVS = {
    "webarena":        "browsergym/webarena.0",
    "visualwebarena":  "browsergym/visualwebarena.0",
    "workarena_l1":    "browsergym/workarena.servicenow.create-incident",
}

def cross_benchmark_eval(agent_cls, task_id_map: dict) -> dict[str, float]:
    results = {}
    for bench_name, env_id in BENCHMARK_ENVS.items():
        env = gym.make(env_id, headless=True)
        obs, info = env.reset()
        agent = agent_cls()

        for _ in range(30):
            action = agent.step(obs)
            obs, reward, terminated, truncated, _ = env.step(action)
            if terminated or truncated:
                break
        env.close()
        results[bench_name] = float(reward)

    return results
